// sigma-attractor.test.ts
// Honest tests for principled sigma selection. The synthetic test plane is a
// 1/f-shaped natural-image surrogate (smooth radial envelope + mid-frequency
// ripple + low-amplitude seeded noise) — the φ-attractor's domain. A pure
// high-frequency checkerboard sits past the PSF's effective passband and is
// information-limited; the selector behaves correctly on it but the ballpark
// it lands in does not match the applied σ, which is a property of the
// signal, not the algorithm.

import { describe, it, expect } from 'vitest';
import { selectSigmaByGoldenAttractor } from '../src/sigma-attractor';
import { applyPSF, gaussianPSF } from '../src/image-psf';
import { PHI } from '../src/attractor';

function lcg(seed: number) {
  let s = seed >>> 0;
  return () => {
    s = (s * 1103515245 + 12345) & 0x7fffffff;
    return s / 0x7fffffff;
  };
}

function buildNaturalishPlane(w: number, h: number, seed: number): Float32Array {
  const plane = new Float32Array(w * h);
  const rand = lcg(seed);
  const cx = w / 2;
  const cy = h / 2;
  // Variance scale: ~ (size/4)² so the radial envelope spans the plane gently.
  const radialScale = (Math.min(w, h) * Math.min(w, h)) / 16;
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const dx = x - cx;
      const dy = y - cy;
      const radial = Math.exp(-(dx * dx + dy * dy) / radialScale);
      const ripple = 0.15 * Math.sin(x / 5) * Math.cos(y / 4);
      const noise = 0.05 * (rand() - 0.5);
      let v = radial + ripple + noise;
      if (v < 0) v = 0;
      if (v > 1) v = 1;
      plane[y * w + x] = v;
    }
  }
  return plane;
}

describe('selectSigmaByGoldenAttractor', () => {
  it('returns the documented shape with default candidate count', () => {
    const w = 64;
    const h = 64;
    const plane = buildNaturalishPlane(w, h, 1);

    const result = selectSigmaByGoldenAttractor({ plane, w, h });

    expect(result).toHaveProperty('selectedSigma');
    expect(result).toHaveProperty('refinedSigma');
    expect(result).toHaveProperty('candidates');
    expect(result).toHaveProperty('bestCandidateIndex');

    expect(result.candidates.length).toBe(7);
    expect(result.candidates[0]!.excludedFromAttractor).toBe(true);

    expect(Number.isFinite(result.selectedSigma)).toBe(true);
    expect(Number.isFinite(result.refinedSigma)).toBe(true);
    for (const c of result.candidates) {
      expect(Number.isFinite(c.sigma)).toBe(true);
      expect(Number.isFinite(c.highBandEnergy)).toBe(true);
      expect(Number.isFinite(c.deficitRatio)).toBe(true);
      expect(Number.isFinite(c.binetResidual)).toBe(true);
    }
  });

  it('throws on non-power-of-2 width', () => {
    const w = 60;
    const h = 64;
    const plane = new Float32Array(w * h);
    expect(() => selectSigmaByGoldenAttractor({ plane, w, h })).toThrow(RangeError);
  });

  it('throws on non-power-of-2 height', () => {
    const w = 64;
    const h = 60;
    const plane = new Float32Array(w * h);
    expect(() => selectSigmaByGoldenAttractor({ plane, w, h })).toThrow(RangeError);
  });

  it('throws when plane.length does not match w*h', () => {
    const w = 64;
    const h = 64;
    const plane = new Float32Array(w * h - 1);
    expect(() => selectSigmaByGoldenAttractor({ plane, w, h })).toThrow(RangeError);
  });

  it('throws on even psfSize', () => {
    const w = 64;
    const h = 64;
    const plane = buildNaturalishPlane(w, h, 2);
    expect(() =>
      selectSigmaByGoldenAttractor({ plane, w, h, psfSize: 10 }),
    ).toThrow(RangeError);
  });

  it('throws on candidateCount < 3', () => {
    const w = 64;
    const h = 64;
    const plane = buildNaturalishPlane(w, h, 3);
    expect(() =>
      selectSigmaByGoldenAttractor({ plane, w, h, candidateCount: 2 }),
    ).toThrow(RangeError);
  });

  it('recovers a sigma within a factor of 3 of sigmaTrue on a 1/f-natural fixture', () => {
    // Loose factor-of-3 bound because (a) the φ-grid is sparse — adjacent
    // candidates differ by a factor of φ ≈ 1.618, so two grid steps already
    // sweep ~2.6× — and (b) the φ-attractor is principled but heuristic;
    // it identifies the inflection point of the local power-law exponent,
    // which need not coincide exactly with sigmaTrue on every signal.
    const w = 64;
    const h = 64;
    const sigmaTrue = 2.0;
    const psfSize = 11;

    const original = buildNaturalishPlane(w, h, 42);
    const psf = gaussianPSF(sigmaTrue, psfSize);
    const blurred = applyPSF({
      plane: original,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
    });

    const result = selectSigmaByGoldenAttractor({
      plane: blurred,
      w,
      h,
      psfSize,
    });

    expect(result.refinedSigma).toBeGreaterThanOrEqual(sigmaTrue / 3);
    expect(result.refinedSigma).toBeLessThanOrEqual(sigmaTrue * 3);
  });

  it('reports finite, non-negative high-band energy for every candidate (Bule cost stability)', () => {
    const w = 64;
    const h = 64;
    const plane = buildNaturalishPlane(w, h, 7);

    const result = selectSigmaByGoldenAttractor({ plane, w, h });

    for (const c of result.candidates) {
      expect(Number.isFinite(c.highBandEnergy)).toBe(true);
      expect(c.highBandEnergy).toBeGreaterThanOrEqual(0);
    }
  });

  it('produces a phi-spaced ascending sigma grid across candidates', () => {
    const w = 64;
    const h = 64;
    const plane = buildNaturalishPlane(w, h, 11);

    const result = selectSigmaByGoldenAttractor({ plane, w, h });

    const sigmas = result.candidates.map((c) => c.sigma);
    for (let i = 1; i < sigmas.length; i++) {
      expect(sigmas[i]!).toBeGreaterThan(sigmas[i - 1]!);
      const ratio = sigmas[i]! / sigmas[i - 1]!;
      expect(Math.abs(ratio - PHI)).toBeLessThan(1e-3);
    }
  });

  it('keeps the Newton-refined sigma within the phi-bracketed clamp window', () => {
    const w = 64;
    const h = 64;
    const sigmaTrue = 2.0;
    const psfSize = 11;

    const original = buildNaturalishPlane(w, h, 99);
    const psf = gaussianPSF(sigmaTrue, psfSize);
    const blurred = applyPSF({
      plane: original,
      w,
      h,
      psf,
      psfW: psfSize,
      psfH: psfSize,
    });

    const result = selectSigmaByGoldenAttractor({
      plane: blurred,
      w,
      h,
      psfSize,
    });

    if (result.bestCandidateIndex >= 1) {
      const lower = result.candidates[result.bestCandidateIndex - 1]!.sigma;
      const upper = result.candidates[result.bestCandidateIndex]!.sigma;
      expect(result.refinedSigma).toBeGreaterThanOrEqual(lower / PHI);
      expect(result.refinedSigma).toBeLessThanOrEqual(upper * PHI);
    }
  });
});
